select *
from batch.workflow_node_run
where workflow_run_id = #{workflowRunId}
  and node_code = #{nodeCode}
order by run_seq desc
limit 1

select distinct on (node_code) *
from batch.workflow_node_run
where workflow_run_id = #{workflowRunId}
  and node_code in
#{c}
order by node_code, run_seq desc

select *
from batch.workflow_node_run
where node_status = #{nodeStatus}
order by id asc
limit #{limit}

mapper.update:
update batch.workflow_node_run
set sensor_next_probe_at = #{nextProbeAt},
    sensor_last_probe_at = #{lastProbeAt},
    sensor_probe_count   = #{probeCount},
    sensor_error_count   = #{errorCount}
where id = #{id}
